import { app, BrowserWindow, type IpcMainInvokeEvent, nativeImage } from "electron";

const ICON_B64 = "";
const catIcon = nativeImage.createFromDataURL("data:image/png;base64," + ICON_B64);

export function applyAppIcon(_: IpcMainInvokeEvent) {
    if (catIcon.isEmpty()) return;

    for (const win of BrowserWindow.getAllWindows()) {
        try {
            win.setIcon(catIcon);
        } catch { }
    }

    if (process.platform === "darwin") {
        try {
            app.dock?.setIcon(catIcon);
        } catch { }
    }
}
